class SidebarContent extends HTMLElement{static get observedAttributes(){return["current-page"]}connectedCallback(){this.render()}attributeChangedCallback(){this.render()}render(){const e=this.getAttribute("current-page")||"",t=window.location.pathname.includes("/pages/")?"":"pages/",n=[{id:"technical-seo",href:t+"technical-seo.html",label:"Техническое SEO"},{id:"semantic-html",href:t+"semantic-html.html",label:"Семантика HTML"},{id:"schema-org",href:t+"schema-org.html",label:"Schema.org"},{id:"json-ld",href:t+"json-ld.html",label:"JSON-LD"},{id:"comparison",href:t+"comparison.html",label:"Сравнение инструментов"},{id:"videos",href:t+"videos.html",label:"Видео"}].map((t=>{const n=t.id===e;return`<li><a href="${t.href}" class="${n?"active":""}">${t.label}</a></li>`})).join("");this.innerHTML=`\n      <div class="container sidebar-content">\n        <h2>Разделы SEO</h2>\n        <ul class="sidebar-nav">\n          ${n}\n        </ul>\n      </div>\n    `}}customElements.define("sidebar-content",SidebarContent);